/**
 * Modular exponentiation: (base^exp) % mod
 * Uses BigInt for safe modular arithmetic since MOD^2 exceeds standard safe integer limit.
 */
function power(base, exp) {
    let res = 1n;
    let b = BigInt(base);
    let e = BigInt(exp);
    const m = 1000000007n;
    b %= m;
    while (e > 0n) {
        if (e % 2n === 1n) {
            res = (res * b) % m;
        }
        b = (b * b) % m;
        e /= 2n;
    }
    return res;
}

function solve(nums1, nums0) {
    const MOD_BIG = 1000000007n;
    const segments = [];

    // 1. Store segments (a1, a0)
    for (let i = 0; i < nums1.length; i++) {
        const a1 = nums1[i];
        const a0 = nums0[i];
        const length = a1 + a0;
        segments.push({ a1, a0, length });
    }

    // 2. Sort segments: A comes before B if A+B > B+A lexicographically.
    segments.sort((A, B) => {
        // If number of ones differs, the one with more ones comes first (descending a1)
        if (A.a1 !== B.a1) {
            return B.a1 - A.a1;
        }
        // If number of ones is equal, prefer the one with fewer zeros (ascending a0)
        return A.a0 - B.a0; 
    });

    // 3. Calculate the total value based on the sorted order
    let totalValue = 0n;
    let currentSuffixLength = 0; // Length of segments placed after the current one (in the final sequence)

    // Iterate backwards through the sorted segments (S_n, S_{n-1}, ..., S_1)
    // This allows us to easily track the cumulative suffix length.
    for (let i = segments.length - 1; i >= 0; i--) {
        const S = segments[i];
        const a1 = S.a1;
        const a0 = S.a0;
        const L = S.length;

        // Calculate V_i = value of segment S_i = 1^a1 0^a0
        let Vi;
        if (a1 === 0) {
            // Segment is 0^a0. Value is 0.
            Vi = 0n;
        } else {
            // V_i = 2^a0 * (2^a1 - 1) mod MOD

            // term1 = 2^a1 - 1
            let term1 = (power(2, a1) - 1n + MOD_BIG) % MOD_BIG;

            // term2 = 2^a0
            let term2 = power(2, a0);

            // V_i = term2 * term1 mod MOD
            Vi = (term2 * term1) % MOD_BIG;
        }

        // Contribution = V_i * 2^(currentSuffixLength) mod MOD

        // powerOf2Suffix = 2^currentSuffixLength mod MOD
        let powerOf2Suffix = power(2, currentSuffixLength);

        // Contribution = Vi * powerOf2Suffix mod MOD
        let contribution = (Vi * powerOf2Suffix) % MOD_BIG;

        totalValue = (totalValue + contribution) % MOD_BIG;

        // Update suffix length for the next segment (i-1)
