// Modular exponentiation: (base^exp) % mod
long long power(long long base, long long exp, long long mod) {
    long long res = 1;
    base %= mod;
    while (exp > 0) {
        if (exp % 2 == 1) {
            res = (res * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }
    return res;
}

struct Segment {
    long long a1;
    long long a0;
    long long length;
};

// Custom comparison function for sorting segments
// A comes before B if it leads to a larger value.
bool compareSegments(const Segment& A, const Segment& B) {
    // 1. Prioritize more ones (descending a1)
    if (A.a1 != B.a1) {
        return A.a1 > B.a1;
    }
    // 2. If a1 is equal, prioritize fewer zeros (ascending a0)
    return A.a0 < B.a0;
}

long long solve(std::vector<long long> nums1, std::vector<long long> nums0) {
    const long long MOD = 1000000007;

    vector<Segment> segments;

    // 1. Store segments
    for (size_t i = 0; i < nums1.size(); ++i) {
        long long a1 = nums1[i];
        long long a0 = nums0[i];
        long long length = a1 + a0;

