        if (length > 0) {
            segments.push_back({a1, a0, length});
        }
    }

    // 2. Sort segments based on the greedy criteria
    sort(segments.begin(), segments.end(), compareSegments);

    // 3. Calculate the total value based on the sorted order
    long long totalValue = 0;
    long long currentSuffixLength = 0; 

    // Iterate backwards through the sorted segments (S_N, S_{N-1}, ..., S_1)
