const long long MOD = 1e9 + 7;

/**
 * Modular exponentiation: (base^exp) % mod
 * Calculates (base^exp) % MOD efficiently.
 */
long long power(long long base, long long exp) {
    long long res = 1;
    base %= MOD;
    while (exp > 0) {
        if (exp % 2 == 1) {
            res = (res * base) % MOD;
        }
        base = (base * base) % MOD;
        exp /= 2;
    }
    return res;
}

